import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office — quote (base premiums)", () => {
  // Edge case: simplest possible
  it.todo("empty item list → premium 5 (only processing fee)");

  // Single main items — base premium + 5 fee, no other modifiers
  // (newcomer 0 years => +10% first insurance applies per item)
  it.todo("single sword (steel, ench 3): 100 base + 10 first + 5 fee → 115");
  it.todo("single amulet (ench 2): 60 base + 6 first + 5 fee → 71");
  it.todo("single staff (ench 1): 80 base + 8 first + 5 fee → 93");
  it.todo("single potion (ench 1): 40 base + 4 first + 5 fee → 49");
});

describe("MHPCO Claim Office — quote (component blocks)", () => {
  it.todo("2 runes → 50 G base premium (no block)");
  it.todo("3 runes → 60 G base premium (block applies)");
  it.todo("4 runes → 100 G base premium (no block — block requires exactly 3)");
  it.todo("7 runes → 175 G base premium");
  it.todo("2 runes + 1 moonstone → 75 G base premium (no block: different types)");
  it.todo("3 runes + 3 moonstones → 120 G base premium (two separate blocks)");
});

describe("MHPCO Claim Office — quote (item-specific modifiers)", () => {
  it.todo("cursed sword adds 50% surcharge on the item base premium");
  it.todo("sword with exactly enchantment 5 → high-enchantment surcharge applies");
  it.todo("sword with enchantment 4 → no high-enchantment surcharge");
  it.todo("cursed sword with enchantment 5 → both curse and high-enchantment surcharges apply");
  it.todo("each item in a quote is treated as a first insurance (+10%) regardless of customer history");
});

describe("MHPCO Claim Office — quote (policy-wide modifiers)", () => {
  it.todo("customer with exactly 2 years → 20% loyalty discount applies");
  it.todo("customer with fewer than 2 years → no loyalty discount");
  it.todo("second quote in scenario → 15% follow-up contract discount applies");
  it.todo("first quote in scenario → no follow-up discount");
});

describe("MHPCO Claim Office — quote (modifier scope on multi-item policies)", () => {
  it.todo("cursed sword (100) + plain amulet (60): base 160, curse adds 50 (on cursed item only) → 210 before fee");
});

describe("MHPCO Claim Office — quote (rounding)", () => {
  it.todo("premium that yields 197.5 G → 198 G (rounded up, MHPCO's favor)");
  it.todo("intermediate amounts kept as fractions; only final premium rounded");
});

describe("MHPCO Claim Office — quote (integration examples)", () => {
  it.todo("newcomer cursed sword (steel, ench 3, 0 years): 100 + 50 curse + 10 first + 5 fee → 165");
  it.todo("long-standing 2nd contract cursed sword (steel, ench 7, 3 years): 100 + 50 + 30 − 20 + 10 − 15 + 5 → 160");
});

describe("MHPCO Claim Office — claim (standard reimbursement)", () => {
  it.todo("regular sword (steel, ench 3), damage 500 → payout 400 (full minus 100 deductible)");
  it.todo("rune (value 250), damage 200 → payout 100 (full minus deductible, no special clause)");
});

describe("MHPCO Claim Office — claim (special clauses)", () => {
  it.todo("dragon-material sword, ench 5, damage 800 → payout 700 (dragon: full then deductible)");
  it.todo("steel sword, ench 9, damage 1000 → payout 400 (high-enchantment 50% then deductible)");
  it.todo("dragon-material sword, ench 8, damage 1000 → payout 400 (high-ench clause applies, then deductible)");
  it.todo("dragon-material sword, ench 9, damage 1000 → payout 400 (both apply, 50% rule wins)");
});

describe("MHPCO Claim Office — claim (deductible per damage event)", () => {
  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 (deductible per item)");
});

describe("MHPCO Claim Office — claim (cap)", () => {
  it.todo("sword + amulet → insurance sum 1600, cap 3200");
  it.todo("cursed sword → cap 2000 (based on unmodified insurance value)");
  it.todo("sword + 3 runes → insurance sum 1750 (block discount does not affect insurance sum)");
  it.todo("two swords → insurance sum 2000, cap 4000");
  it.todo("sword (cap 2000), two claims of 1500: first payout 1400 remaining 600; second payout 600 remaining 0");
});

describe("MHPCO Claim Office — claim (multiple items of same type)", () => {
  it.todo("two swords insured, both damaged → each damage entry gets its own deductible");
  it.todo("two sword damages but only one sword insured → reject (non-zero exit)");
});

describe("MHPCO Claim Office — claim (payout rounding)", () => {
  it.todo("payout that yields 350.5 G → 350 G (rounded down)");
});

describe("MHPCO Claim Office — error handling", () => {
  it.todo("quote with unknown item type → throws / non-zero exit");
  it.todo("claim referencing an item not in the policy → throws / non-zero exit");
  it.todo("claim referencing an unknown item type → throws / non-zero exit");
  it.todo("claim with a negative damage amount → throws / non-zero exit");
});

describe("MHPCO Claim Office — CLI scenario integration", () => {
  it.todo("schema example: quote amulet then claim → results aligned to steps");
});

