interface Item {
  type: string;
}

interface QuoteStep {
  op: "quote";
  items: Item[];
}

interface Scenario {
  customer: { yearsWithMHPCO: number };
  steps: QuoteStep[];
}

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
};

const quotePremium = (items: Item[]): number => {
  let total = 0;
  for (const item of items) {
    const base = BASE_PREMIUM[item.type];
    total += base * 1.1;
  }
