interface Item {
  type: string;
}

interface QuoteStep {
  op: "quote";
  items: Item[];
}

interface Scenario {
  customer: { yearsWithMHPCO: number };
  steps: QuoteStep[];
}

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
};

const FIRST_INSURANCE_MULTIPLIER = 1.1;
const PROCESSING_FEE = 5;
const ROUNDING_PRECISION = 6;

const quotePremium = (items: Item[]): number => {
  let total = 0;
  for (const item of items) {
    const base = BASE_PREMIUM[item.type];
    total += base * FIRST_INSURANCE_MULTIPLIER;
  }
  const totalWithFee = total + PROCESSING_FEE;
  return Math.ceil(Number(totalWithFee.toFixed(ROUNDING_PRECISION)));
};

export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
  return { results };
};

