interface Item {
  type: string;
}

interface QuoteStep {
  op: "quote";
  items: Item[];
}

interface Scenario {
  customer: { yearsWithMHPCO: number };
  steps: QuoteStep[];
}

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const COMPONENT_BASE = 25;
const BLOCK_SIZE = 3;
const BLOCK_BASE = 60;

const FIRST_INSURANCE_MULTIPLIER = 1.1;
const PROCESSING_FEE = 5;
const ROUNDING_PRECISION = 6;

const componentGroupBase = (count: number): number => {
  const blocks = Math.floor(count / BLOCK_SIZE);
  const remainder = count % BLOCK_SIZE;
  return blocks * BLOCK_BASE + remainder * COMPONENT_BASE;
};

const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);

const mainItemBase = (items: Item[]): number =>
  items
    .filter((item) => !isComponent(item))
    .reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);

const componentBase = (items: Item[]): number => {
  const counts: Record<string, number> = {};
  for (const item of items.filter(isComponent)) {
    counts[item.type] = (counts[item.type] ?? 0) + 1;
  }
  return Object.values(counts).reduce((sum, count) => sum + componentGroupBase(count), 0);
};

const roundUpToWhole = (amount: number): number =>
  Math.ceil(Number(amount.toFixed(ROUNDING_PRECISION)));

const quotePremium = (items: Item[]): number => {
  const base = mainItemBase(items) + componentBase(items);
  return roundUpToWhole(base * FIRST_INSURANCE_MULTIPLIER + PROCESSING_FEE);
};

export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
  return { results };
};

