interface Item {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
}

interface QuoteStep {
  op: "quote";
  items: Item[];
}

interface Scenario {
  customer: { yearsWithMHPCO: number };
  steps: QuoteStep[];
}

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const COMPONENT_BASE = 25;
const BLOCK_SIZE = 3;
const BLOCK_BASE = 60;

const FIRST_INSURANCE_RATE = 0.1;
const CURSE_RATE = 0.5;
const PROCESSING_FEE = 5;
const ROUNDING_PRECISION = 6;

const componentGroupBase = (count: number): number =>
  count === BLOCK_SIZE ? BLOCK_BASE : count * COMPONENT_BASE;

const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);

const withSurcharge = (base: number, rate: number): number => base + base * rate;

const mainItemPremium = (item: Item): number => {
  const base = BASE_PREMIUM[item.type];
  const surchargeRate = FIRST_INSURANCE_RATE + (item.cursed ? CURSE_RATE : 0);
  return withSurcharge(base, surchargeRate);
};

const mainItemTotal = (items: Item[]): number =>
  items
    .filter((item) => !isComponent(item))
    .reduce((sum, item) => sum + mainItemPremium(item), 0);

const componentTotal = (items: Item[]): number => {
  const counts: Record<string, number> = {};
  for (const item of items.filter(isComponent)) {
    counts[item.type] = (counts[item.type] ?? 0) + 1;
  }
  const base = Object.values(counts).reduce((sum, count) => sum + componentGroupBase(count), 0);
  return withSurcharge(base, FIRST_INSURANCE_RATE);
};

const roundUpToWhole = (amount: number): number =>
  Math.ceil(Number(amount.toFixed(ROUNDING_PRECISION)));

const quotePremium = (items: Item[]): number =>
  roundUpToWhole(mainItemTotal(items) + componentTotal(items) + PROCESSING_FEE);

export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
  return { results };
};

